var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"으으......","JPN":"うぅ……","ENG":"Ugh...","TWN":"呃呃……"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"오지 마! 안 돼! 그런 멋대가리 없는 X자는 죽어도 싫어!","JPN":"来ないで！　イヤ！　そのダサイX印は死んでもイヤ！","ENG":"No, no! Don't get near me! I don't want that tacky-looking X on my forehead!","TWN":"不要過來！走開！我才不要在額頭印上那麼蠢的X呢！"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"정신이 들었군요. 실비아 씨.","JPN":"気がつきましたか、シルビアさん！","ENG":"You're awake, Sylvia.","TWN":"妳醒啦，希爾維亞？"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"몸은 괜찮은가요?","JPN":"体は大丈夫ですか？","ENG":"How do you feel?","TWN":"身體感覺怎麼樣？"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"부, 부사장 아줌마? 어떻게 여기에......?","JPN":"副社長のおばさん？　なんで……ここに？","ENG":"V-Vice President Lady? What are you doing here?","TWN":"副、副總大嬸？妳怎麼在這裡……？"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아줌마 아니라니까 언제쯤 그 말버릇이 고쳐질지 모르겠군요.","JPN":"おばさんじゃありません。いつになったらちゃんとした言葉遣いを覚えるんですか？","ENG":"I don't know how many times I told you not to call me lady.","TWN":"我不是大嬸，妳什麼時候才能改掉那亂叫的毛病。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"긴급상황이 벌어진 걸 확인하고 조금 전에 급히 도착했습니다.","JPN":"緊急事態が発生したことを確認し、先ほど駆けつけたんです。","ENG":"Just a few minutes ago. I came as soon as I confirmed the situation.","TWN":"在確認發生了緊急狀況後，我就馬上過來了。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"폭설이라 교통편도 없어서 계약했던 임무까지 취소하고 코핀 함으로 달려왔죠.","JPN":"大雪で交通手段もなかったので、契約していた任務までキャンセルしてコフィン艦で来たんです。","ENG":"No car couldn't get here through the heavy snowfall, so I cancelled a contract mission and flew here in the Coffin.","TWN":"因為暴風雪沒辦法坐交通工具來，所以我把任務都取消後直接通過科芬艦來的。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"누가 됐든 이 소동을 일으킨 당사자는 저희 회사가 입은 손해에 대해 책임을 져야 할 겁니다.","JPN":"誰だろうと、この騒動を起こした当事者には当社が負った損害の責任を取ってもらいます。","ENG":"Whoever has caused this trouble will have to pay for the damage that our company has sustained.","TWN":"無論是誰引起了這場騷亂，都將為我們公司遭受的損失承擔責任。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아주 확실한 책임을 말이죠.","JPN":"きっちり、耳をそろえて。","ENG":"I'll make sure of it.","TWN":"而且是非常確切的責任。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"나, 난 아니니까 그렇게 노려보지 마.","JPN":"あ、アタシじゃないから！　そんな目で見ないでよ。","ENG":"I-I didn't do it. Don't glare at me like that.","TWN":"不、不是我做的，別那樣瞪我。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"그보다 다른 사람들은? 다들 무사해?","JPN":"それより他の人たちは？　みんな無事なの？","ENG":"What about the others? Are they all okay now?","TWN":"其他人呢？都安全了嗎？"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"특별히 다친 사람은 없었습니다. 마침 저기 오는군요.","JPN":"特に怪我人はいませんでした。ああ、ちょうどいらしたようです。","ENG":"No one got hurt too badly. There they come.","TWN":"沒人受傷。她們過來了。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"실비아! 타이밍 좋게 깨어났군.","JPN":"シルビア！　いいタイミングで目を覚ましたようだな。","ENG":"Sylvia! You woke up at the right time.","TWN":"希爾維亞！妳醒的真是時候。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"제이크! 카일은?","JPN":"ジェイク！　カイルは？","ENG":"Jake! Where's Kyle?","TWN":"傑克！凱爾呢？"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"저도 옆에 있습니다......","JPN":"僕も隣にいます……","ENG":"I'm here...","TWN":"我在這裡……"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......머리가 울리니까 소리치지 말아주십쇼.","JPN":"……頭に響くので、大声出さないでください。","ENG":"Please stop yelling. My head is throbbing.","TWN":"……妳能不能別叫了，只會讓我更暈。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};